29	#define MAX4(a,b,c,d) fz_max(fz_max(a,b), fz_max(c,d))
30	#define MIN4(a,b,c,d) fz_min(fz_min(a,b), fz_min(c,d))
31	
32	/*	A useful macro to add with overflow detection and clamping.
33	
34		We want to do "b = a + x", but to allow for overflow. Consider the
35		top bits, and the cases in which overflow occurs:
36	
37		overflow    a   x   b ~a^x  a^b   (~a^x)&(a^b)
38		   no       0   0   0   1    0          0
39		   yes      0   0   1   1    1          1
40		   no       0   1   0   0    0          0
41		   no       0   1   1   0    1          0
42		   no       1   0   0   0    1          0
43		   no       1   0   1   0    0          0
44		   yes      1   1   0   1    1          1
45		   no       1   1   1   1    0          0
46	*/
47	#define ADD_WITH_SAT(b,a,x) \
48		((b) = (a) + (x), (b) = (((~(a)^(x))&((a)^(b))) < 0 ? ((x) < 0 ? INT_MIN : INT_MAX) : (b)))
49	
50	/* Matrices, points and affine transformations */
51	
52	const fz_matrix fz_identity = { 1, 0, 0, 1, 0, 0 };
53	
54	fz_matrix
55	fz_concat(fz_matrix one, fz_matrix two)
56	{
57		fz_matrix dst;
58		dst.a = one.a * two.a + one.b * two.c;
59		dst.b = one.a * two.b + one.b * two.d;
60		dst.c = one.c * two.a + one.d * two.c;
61		dst.d = one.c * two.b + one.d * two.d;
62		dst.e = one.e * two.a + one.f * two.c + two.e;
63		dst.f = one.e * two.b + one.f * two.d + two.f;
64		return dst;
65	}
66	
67	fz_matrix
68	fz_scale(float sx, float sy)
69	{
70		fz_matrix m;
71		m.a = sx; m.b = 0;
72		m.c = 0; m.d = sy;
73		m.e = 0; m.f = 0;
74		return m;
75	}
76	
77	fz_matrix
78	fz_pre_scale(fz_matrix m, float sx, float sy)
79	{
80		m.a *= sx;
81		m.b *= sx;
82		m.c *= sy;
83		m.d *= sy;
84		return m;
85	}
86	
87	fz_matrix
88	fz_post_scale(fz_matrix m, float sx, float sy)
89	{
90		m.a *= sx;
91		m.b *= sy;
92		m.c *= sx;
93		m.d *= sy;
94		m.e *= sx;
95		m.f *= sy;
96		return m;
97	}
98	
99	fz_matrix
100	fz_shear(float h, float v)
101	{
102		fz_matrix m;
103		m.a = 1; m.b = v;
104		m.c = h; m.d = 1;
105		m.e = 0; m.f = 0;
106		return m;
107	}
108	
109	fz_matrix
110	fz_pre_shear(fz_matrix m, float h, float v)
111	{
112		float a = m.a;
113		float b = m.b;
114		m.a += v * m.c;
115		m.b += v * m.d;
116		m.c += h * a;
117		m.d += h * b;
118		return m;
119	}
120	
121	fz_matrix
122	fz_rotate(float theta)
123	{
124		fz_matrix m;
125		float s;
126		float c;
127	
128		theta = fmod(theta, 360);
129		if (theta < 0)
130			theta += 360;
131	
132		if (fabsf(0 - theta) < FLT_EPSILON)
133		{
134			s = 0;
135			c = 1;
136		}
137		else if (fabsf(90.0f - theta) < FLT_EPSILON)
138		{
139			s = 1;
140			c = 0;
141		}
142		else if (fabsf(180.0f - theta) < FLT_EPSILON)
143		{
144			s = 0;
145			c = -1;
146		}
147		else if (fabsf(270.0f - theta) < FLT_EPSILON)
148		{
149			s = -1;
150			c = 0;
151		}
152		else
153		{
154			s = sinf(theta * FZ_PI / 180);
155			c = cosf(theta * FZ_PI / 180);
156		}
157	
158		m.a = c; m.b = s;
159		m.c = -s; m.d = c;
160		m.e = 0; m.f = 0;
161		return m;
162	}
163	
164	fz_matrix
165	fz_pre_rotate(fz_matrix m, float theta)
166	{
167		theta = fmod(theta, 360);
168		if (theta < 0)
169			theta += 360;
170	
171		if (fabsf(0 - theta) < FLT_EPSILON)
172		{
173			/* Nothing to do */
174		}
175		else if (fabsf(90.0f - theta) < FLT_EPSILON)
176		{
177			float a = m.a;
178			float b = m.b;
179			m.a = m.c;
180			m.b = m.d;
181			m.c = -a;
182			m.d = -b;
183		}
184		else if (fabsf(180.0f - theta) < FLT_EPSILON)
185		{
186			m.a = -m.a;
187			m.b = -m.b;
188			m.c = -m.c;
189			m.d = -m.d;
190		}
191		else if (fabsf(270.0f - theta) < FLT_EPSILON)
192		{
193			float a = m.a;
194			float b = m.b;
195			m.a = -m.c;
196			m.b = -m.d;
197			m.c = a;
198			m.d = b;
199		}
200		else
201		{
202			float s = sinf(theta * FZ_PI / 180);
203			float c = cosf(theta * FZ_PI / 180);
204			float a = m.a;
205			float b = m.b;
206			m.a = c * a + s * m.c;
207			m.b = c * b + s * m.d;
208			m.c =-s * a + c * m.c;
209			m.d =-s * b + c * m.d;
210		}
211	
212		return m;
213	}
214	
215	fz_matrix
216	fz_translate(float tx, float ty)
217	{
218		fz_matrix m;
219		m.a = 1; m.b = 0;
220		m.c = 0; m.d = 1;
221		m.e = tx; m.f = ty;
222		return m;
223	}
224	
225	fz_matrix
226	fz_pre_translate(fz_matrix m, float tx, float ty)
227	{
228		m.e += tx * m.a + ty * m.c;
229		m.f += tx * m.b + ty * m.d;
230		return m;
231	}
232	
233	fz_matrix
234	fz_transform_page(fz_rect mediabox, float resolution, float rotate)
235	{
236		float user_w, user_h, pixel_w, pixel_h;
237		fz_rect pixel_box;
238		fz_matrix matrix;
239	
240		/* Adjust scaling factors to cover whole pixels */
241		user_w = mediabox.x1 - mediabox.x0;
242		user_h = mediabox.y1 - mediabox.y0;
243		pixel_w = floorf(user_w * resolution / 72 + 0.5f);
244		pixel_h = floorf(user_h * resolution / 72 + 0.5f);
245	
246		matrix = fz_pre_rotate(fz_scale(pixel_w / user_w, pixel_h / user_h), rotate);
247	
248		/* Adjust the page origin to sit at 0,0 after rotation */
249		pixel_box = fz_transform_rect(mediabox, matrix);
250		matrix.e -= pixel_box.x0;
251		matrix.f -= pixel_box.y0;
252	
253		return matrix;
254	}
255	
256	fz_matrix
257	fz_invert_matrix(fz_matrix src)
258	{
259		double sa = (double)src.a;
260		double sb = (double)src.b;
261		double sc = (double)src.c;
262		double sd = (double)src.d;
263		double da, db, dc, dd, de, df;
264		double det = sa * sd - sb * sc;
265		// If we cannot invert the matrix, return a degenerate one so we can
266		// more easily spot it when debugging!
267		if (det >= -DBL_EPSILON && det <= DBL_EPSILON)
268			return fz_make_matrix(0, 0, 0, 0, 0, 0);
269		det = 1 / det;
270		da = sd * det;
271		db = -sb * det;
272		dc = -sc * det;
273		dd = sa * det;
274		de = -src.e * da - src.f * dc;
275		df = -src.e * db - src.f * dd;
276		return fz_make_matrix(da, db, dc, dd, de, df);
277	}
278	
279	int
280	fz_try_invert_matrix(fz_matrix *dst, fz_matrix src)
281	{
282		double sa = (double)src.a;
283		double sb = (double)src.b;
284		double sc = (double)src.c;
285		double sd = (double)src.d;
286		double da, db, dc, dd;
287		double det = sa * sd - sb * sc;
288		if (det >= -DBL_EPSILON && det <= DBL_EPSILON)
289			return 1;
290		det = 1 / det;
291		da = sd * det;
292		dst->a = (float)da;
293		db = -sb * det;
294		dst->b = (float)db;
295		dc = -sc * det;
296		dst->c = (float)dc;
297		dd = sa * det;
298		dst->d = (float)dd;
299		da = -src.e * da - src.f * dc;
300		dst->f = (float)(-src.e * db - src.f * dd);
301		dst->e = (float)da;
302		return 0;
303	}
