410	fz_rect
411	fz_rect_from_irect(fz_irect a)
412	{
413		fz_rect r;
414	
415		if (fz_is_infinite_irect(a))
416			return fz_infinite_rect;
417	
418		r.x0 = a.x0;
419		r.y0 = a.y0;
420		r.x1 = a.x1;
421		r.y1 = a.y1;
422		return r;
423	}
