443	fz_rect
444	fz_intersect_rect(fz_rect a, fz_rect b)
445	{
446		if (fz_is_infinite_rect(b)) return a;
447		if (fz_is_infinite_rect(a)) return b;
448		if (a.x0 < b.x0)
449			a.x0 = b.x0;
450		if (a.y0 < b.y0)
451			a.y0 = b.y0;
452		if (a.x1 > b.x1)
453			a.x1 = b.x1;
454		if (a.y1 > b.y1)
455			a.y1 = b.y1;
456		return a;
457	}
