460	fz_intersect_irect(fz_irect a, fz_irect b)
461	{
462		if (fz_is_infinite_irect(b)) return a;
463		if (fz_is_infinite_irect(a)) return b;
464		if (a.x0 < b.x0)
465			a.x0 = b.x0;
466		if (a.y0 < b.y0)
467			a.y0 = b.y0;
468		if (a.x1 > b.x1)
469			a.x1 = b.x1;
470		if (a.y1 > b.y1)
