645	int fz_contains_rect(fz_rect a, fz_rect b)
646	{
647		/* An invalid rect can't contain anything */
648		if (!fz_is_valid_rect(a))
649			return 0;
650		/* Any valid rect contains all invalid rects */
651		if (!fz_is_valid_rect(b))
652			return 1;
653		return ((a.x0 <= b.x0) &&
654			(a.y0 <= b.y0) &&
655			(a.x1 >= b.x1) &&
656			(a.y1 >= b.y1));
