664	int
665	fz_is_valid_quad(fz_quad q)
666	{
667		return (!isnan(q.ll.x) &&
668			!isnan(q.ll.y) &&
669			!isnan(q.ul.x) &&
670			!isnan(q.ul.y) &&
671			!isnan(q.lr.x) &&
672			!isnan(q.lr.y) &&
673			!isnan(q.ur.x) &&
674			!isnan(q.ur.y));
675	}
676	
677	int
678	fz_is_infinite_quad(fz_quad q)
679	{
680		/* For a quad to be infinite, all the ordinates need to be infinite. */
681		if (!isinf(q.ll.x) ||
682			!isinf(q.ll.y) ||
683			!isinf(q.ul.x) ||
684			!isinf(q.ul.y) ||
685			!isinf(q.lr.x) ||
686			!isinf(q.lr.y) ||
687			!isinf(q.ur.x) ||
688			!isinf(q.ur.y))
689			return 0;
690	
691		/* Just because all the ordinates are infinite, we don't necessarily have an infinite quad. */
692		/* The quad points in order are: ll, ul, ur, lr  OR  reversed:  ll, lr, ur, ul */
693		/* The required points are: (-inf, -inf) (-inf, inf) (inf, inf) (inf, -inf) */
694	
695		/* Not the fastest way to code it, but easy to understand! */
696	#define INF_QUAD_TEST(A,B,C,D) \
697		if (q.A.x < 0 && q.A.y < 0 && q.B.x < 0 && q.B.y > 0 && q.C.x > 0 && q.C.y > 0 && q.D.x > 0 && q.D.y < 0) return 1
698	
699		INF_QUAD_TEST(ll, ul, ur, lr);
700		INF_QUAD_TEST(ul, ur, lr, ll);
701		INF_QUAD_TEST(ur, lr, ll, ul);
702		INF_QUAD_TEST(lr, ll, ul, ur);
703		INF_QUAD_TEST(ll, lr, ur, ul);
704		INF_QUAD_TEST(lr, ur, ul, ll);
705		INF_QUAD_TEST(ur, ul, ll, lr);
706		INF_QUAD_TEST(ul, ll, lr, ur);
707	#undef INF_QUAD_TEST
708	
709		return 0;
710	}
711	
712	int fz_is_empty_quad(fz_quad q)
713	{
714		/* Using "Shoelace" formula */
715		float area;
716	
717		if (fz_is_infinite_quad(q))
718			return 0;
719		if (!fz_is_valid_quad(q))
720			return 1; /* All invalid quads are empty */
721	
722		area = q.ll.x * q.lr.y +
723			q.lr.x * q.ur.y +
724			q.ur.x * q.ul.y +
725			q.ul.x * q.ll.y -
726			q.lr.x * q.ll.y -
727			q.ur.x * q.lr.y -
728			q.ul.x * q.ur.y -
729			q.ll.x * q.ul.y;
730	
731		return area == 0;
732	}
