734	fz_rect
735	fz_rect_from_quad(fz_quad q)
736	{
737		fz_rect r;
738	
739		if (!fz_is_valid_quad(q))
740			return fz_invalid_rect;
741		if (fz_is_infinite_quad(q))
742			return fz_infinite_rect;
743	
744		r.x0 = MIN4(q.ll.x, q.lr.x, q.ul.x, q.ur.x);
745		r.y0 = MIN4(q.ll.y, q.lr.y, q.ul.y, q.ur.y);
746		r.x1 = MAX4(q.ll.x, q.lr.x, q.ul.x, q.ur.x);
747		r.y1 = MAX4(q.ll.y, q.lr.y, q.ul.y, q.ur.y);
748		return r;
749	}
