752	fz_transform_quad(fz_quad q, fz_matrix m)
753	{
754		if (!fz_is_valid_quad(q))
755			return q;
756		if (fz_is_infinite_quad(q))
757			return q;
758	
759		q.ul = fz_transform_point(q.ul, m);
760		q.ur = fz_transform_point(q.ur, m);
761		q.ll = fz_transform_point(q.ll, m);
762		q.lr = fz_transform_point(q.lr, m);
763		return q;
764	}
