807		if (!fz_is_valid_irect(outer))
808			return 0;
809		if (!fz_is_valid_irect(inner))
810			return 0;
811		if (inner.x0 >= outer.x0 && inner.x1 <= outer.x1 && inner.y0 >= outer.y0 && inner.y1 <= outer.y1)
812			return 1;
813		return 0;
814	}
815	
816	/* cross (b-a) with (p-a) */
817	static float
818	cross(fz_point a, fz_point b, fz_point p)
819	{
820		b.x -= a.x;
821		b.y -= a.y;
822		p.x -= a.x;
823		p.y -= a.y;
824		return b.x * p.y - b.y * p.x;
825	}
826	
827	static int fz_is_point_inside_triangle(fz_point p, fz_point a, fz_point b, fz_point c)
828	{
829		/* Consider the following:
830		 *
831		 *       P
832		 *      /|
833		 *     / |
834		 *    /  |
835		 * A +---+-------+ B
836		 *       M
837		 *
838		 * The cross product of vector AB and vector AP is the distance PM.
839		 * The sign of this distance depends on what side of the line AB, P lies on.
840		 *
841		 * So, for a triangle ABC, if we take cross products of:
842		 *
843		 *  AB and AP
844		 *  BC and BP
845		 *  CA and CP
846		 *
847		 * P can only be inside the triangle if the signs are all identical.
848		 *
849		 * One of the cross products being 0 indicates that the point is on a line.
850		 * Two of the cross products being 0 indicates that the point is on a vertex.
851		 *
852		 * If 2 of the vertices are the same, the algorithm still works.
853		 * Iff all 3 of the vertices are the same, the cross products are all zero. The
854		 * value of p is irrelevant.
855		 */
856		float crossa = cross(a, b, p);
857		float crossb = cross(b, c, p);
858		float crossc = cross(c, a, p);
859	
860		/* Check for degenerate case. All vertices the same. */
861		if (crossa == 0 && crossb == 0 && crossc == 0)
862			return a.x == p.x && a.y == p.y;
863	
864		if (crossa >= 0 && crossb >= 0 && crossc >= 0)
865			return 1;
866		if (crossa <= 0 && crossb <= 0 && crossc <= 0)
867			return 1;
868	
869		return 0;
870	}
871	
872	int fz_is_point_inside_quad(fz_point p, fz_quad q)
873	{
874		if (!fz_is_valid_quad(q))
875			return 0;
876		if (fz_is_infinite_quad(q))
877			return 1;
878	
879		return
880			fz_is_point_inside_triangle(p, q.ul, q.ur, q.lr) ||
881			fz_is_point_inside_triangle(p, q.ul, q.lr, q.ll);
882	}
883	
884	int fz_is_quad_inside_quad(fz_quad needle, fz_quad haystack)
885	{
886		if (!fz_is_valid_quad(needle) || !fz_is_valid_quad(haystack))
887			return 0;
888		if (fz_is_infinite_quad(haystack))
889			return 1;
890	
891		return
892			fz_is_point_inside_quad(needle.ul, haystack) &&
893			fz_is_point_inside_quad(needle.ur, haystack) &&
894			fz_is_point_inside_quad(needle.ll, haystack) &&
895			fz_is_point_inside_quad(needle.lr, haystack);
896	}
897	
898	int fz_is_quad_intersecting_quad(fz_quad a, fz_quad b)
899	{
900		fz_rect ar = fz_rect_from_quad(a);
901		fz_rect br = fz_rect_from_quad(b);
902		return !fz_is_empty_rect(fz_intersect_rect(ar, br));
903	}
904	
905	/* ckd_mul, ckd_add and ckd_sub on signed integers */
906	
907	#ifndef HAVE_STDCKDINT_H
908	
909	int fz_ckd_mul_i32(int32_t *out, int32_t a, int32_t b)
910	{
911		int64_t big = (int64_t)a * (int64_t)b;
912		*out = (int32_t)big;
913		return (int64_t)*out != big;
914	}
915	
916	int fz_ckd_add_i32(int32_t *out, int32_t a, int32_t b)
917	{
918		*out = a + b;
919		// adding + to - will never overflow.
920		// if adding two +, expect + result.
921		// if adding two -, expect - result.
922		// overflow if inputs are same sign and output is not that sign.
923		return ((a < 0) == (b < 0) && (a < 0) != (*out < 0));
924	}
925	
926	int fz_ckd_sub_i32(int32_t *out, int32_t a, int32_t b)
927	{
928		*out = a - b;
929		// subtracting + from + will never overflow.
930		// subtracting - from - will never overflow.
931		// subtracting - from +, expect +.
932		// subtracting + from -, expect -.
933		// overflow if inputs vary in sign and output does not have same sign as first input.
934		return ((a < 0) != (b < 0) && (a < 0) != (*out < 0));
935	}
936	
937	int fz_ckd_mul_int(int *out, int a, int b)
938	{
939		int64_t big = (int64_t)a * (int64_t)b;
940		*out = (int)big;
941		return (int64_t)*out != big;
942	}
943	
944	int fz_ckd_add_int(int *out, int a, int b)
945	{
946		*out = a + b;
947		return ((a < 0) == (b < 0) && (a < 0) != (*out < 0));
948	}
949	
950	int fz_ckd_sub_int(int *out, int a, int b)
951	{
952		*out = a - b;
953		return ((a < 0) != (b < 0) && (a < 0) != (*out < 0));
954	}
955	
956	/* ckd_mul, ckd_add and ckd_sub on unsigned integers */
957	
958	int fz_ckd_mul_u32(uint32_t *out, uint32_t a, uint32_t b)
959	{
960		uint64_t big = (uint64_t)a * (uint64_t)b;
961		*out = (uint32_t)big;
962		return (uint64_t)*out != big;
963	}
964	
965	int fz_ckd_add_u32(uint32_t *out, uint32_t a, uint32_t b)
966	{
967		*out = a + b;
968		return *out < a;
969	}
970	
971	int fz_ckd_sub_u32(uint32_t *out, uint32_t a, uint32_t b)
972	{
973		*out = a - b;
974		return a < b;
975	}
976	
977	int fz_ckd_mul_uint(unsigned int *out, unsigned int a, unsigned int b)
978	{
979		uint64_t big = (uint64_t)a * (uint64_t)b;
980		*out = (unsigned int)big;
981		return (uint64_t)*out != big;
982	}
983	
984	int fz_ckd_add_uint(unsigned int *out, unsigned int a, unsigned int b)
985	{
986		*out = a + b;
987		return *out < a;
988	}
989	
990	int fz_ckd_sub_uint(unsigned int *out, unsigned int a, unsigned int b)
991	{
992		*out = a - b;
993		return a < b;
994	}
995	
996	int fz_ckd_mul_size(size_t *out, size_t a, size_t b)
997	{
998		/* Try and avoid the division if we can. */
999		if (sizeof(size_t) == sizeof(int64_t))
1000		{
1001			*out = a * b;
1002			if (b != 0 && a != *out/b)
1003				return 1;
1004			return 0;
1005		}
1006		else if (a <= UINT32_MAX && b <= UINT32_MAX)
1007		{
1008			uint32_t x;
1009			if (fz_ckd_mul_u32(&x, (uint32_t)a, (uint32_t)b))
1010				return 1;
1011			*out = x;
1012			return 0;
1013		}
1014		return 1;
1015	}
1016	
1017	int fz_ckd_add_size(size_t *out, size_t a, size_t b)
1018	{
1019		*out = a + b;
1020		return *out < a;
1021	}
1022	
1023	int fz_ckd_sub_size(size_t *out, size_t a, size_t b)
1024	{
1025		*out = a - b;
1026		return a < b;
1027	}
1028	
1029	int fz_ckd_mul_i64(int64_t *out, int64_t a, int64_t b)
1030	{
1031		*out = a * b;
1032		if (b != 0 && a != *out/b)
1033			return 1;
1034		return 0;
1035	}
1036	
1037	int fz_ckd_add_i64(int64_t *out, int64_t a, int64_t b)
1038	{
1039		*out = a + b;
1040		return *out < a;
1041	}
1042	
1043	int fz_ckd_sub_i64(int64_t *out, int64_t a, int64_t b)
1044	{
1045		*out = a - b;
1046		return a < b;
1047	}
1048	
1049	
1050	int fz_ckd_mul_u64(uint64_t *out, uint64_t a, uint64_t b)
1051	{
1052		*out = a * b;
1053		if (b != 0 && a != *out/b)
1054			return 1;
1055		return 0;
1056	}
1057	
1058	int fz_ckd_add_u64(uint64_t *out, uint64_t a, uint64_t b)
1059	{
1060		*out = a + b;
1061		return *out < a;
1062	}
1063	
1064	int fz_ckd_sub_u64(uint64_t *out, uint64_t a, uint64_t b)
1065	{
1066		*out = a - b;
1067		return a < b;
1068	}
1069	
1070	#endif
1071	
1072	int fz_ckd_size_from_i64(size_t *out, int64_t in)
1073	{
1074		if (in < 0 || (sizeof(int64_t) > sizeof(size_t) && in > (int64_t)SIZE_MAX))
1075			return 1;
1076		*out = (size_t)in;
1077		return 0;
1078	}
1079	
1080	int fz_ckd_int_from_i64(int *out, int64_t in)
1081	{
1082		if (in < 0 || (sizeof(int64_t) > sizeof(int) && in > (int64_t)INT_MAX))
1083			return 1;
1084		*out = (int)in;
1085		return 0;
1086	}
